mapper.select:
SELECT exception_type AS exceptionType, exception_message AS normalizedMsg, exception_message AS sampleMessage, serviceName, count() AS totalCount, min(timestamp) AS firstSeen, max(timestamp) AS lastSeen FROM logs WHERE level = 'ERROR' AND exception_type != '' AND timestamp >= toDateTime64(#{params.startTime}, 3) AND timestamp <= toDateTime64(#{params.endTime}, 3)
AND service_name = #{params.serviceName}
GROUP BY service_name, exception_type, exception_message ORDER BY totalCount DESC LIMIT #{params.limit}

SELECT exception_type AS exceptionType, exception_message AS normalizedMsg, count() AS totalCount, uniqExact(toDate(timestamp)) AS occurrenceDays, count() / uniqExact(toDate(timestamp)) AS avgPerDay, min(timestamp) AS firstSeen, max(timestamp) AS lastSeen FROM logs WHERE level = 'ERROR' AND exception_type != '' AND timestamp >= toDateTime64(#{params.startTime}, 3) AND timestamp <= toDateTime64(#{params.endTime}, 3)
AND service_name = #{params.serviceName}
GROUP BY exception_type, exception_message ORDER BY totalCount DESC LIMIT 20
